const crypto = require('crypto');
const https = require('https');
const { URL } = require('url');

function httpsRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode, body: data }));
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const issue = $input.first().json.query.issue;
const token = $input.first().json.query.token;

// Validate params
if (!issue || !token) {
  return [{ json: { redirectURL: 'https://github.com/stoa-platform/stoa' } }];
}

// Validate HMAC
const secret = $env.APPROVE_HMAC_SECRET;
if (!secret) {
  return [{ json: { redirectURL: 'https://github.com/stoa-platform/stoa' } }];
}
const expected = crypto.createHmac('sha256', secret).update(issue).digest('hex');
if (token !== expected) {
  return [{ json: { redirectURL: 'https://github.com/stoa-platform/stoa' } }];
}

// Post /go comment
try {
  const pat = $env.GITHUB_PAT;
  const postBody = JSON.stringify({ body: '/go' });
  const url = new URL(`https://api.github.com/repos/stoa-platform/stoa/issues/${issue}/comments`);
  const res = await httpsRequest({
    hostname: url.hostname,
    path: url.pathname,
    method: 'POST',
    headers: {
      'Authorization': `token ${pat}`,
      'Accept': 'application/vnd.github.v3+json',
      'Content-Type': 'application/json',
      'User-Agent': 'n8n-stoa-factory',
      'Content-Length': Buffer.byteLength(postBody)
    }
  }, postBody);

  return [{ json: { redirectURL: `https://github.com/stoa-platform/stoa/issues/${issue}` } }];
} catch (e) {
  return [{ json: { redirectURL: `https://github.com/stoa-platform/stoa/issues/${issue}` } }];
}
